(function(){
  try {
    var result = {};
    var allText = [];
    var walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, null, false);
    var node;
    while (node = walker.nextNode()) {
      var t = node.textContent.trim();
      if (t) allText.push(t);
    }
    result.allText = allText.slice(0, 100);
    for (var i = 0; i < allText.length; i++) {
      var t = allText[i];
      if (t === '元' && i > 0 && allText[i-1].match(/^[0-9]+$/)) result.money = parseInt(allText[i-1]);
      if (t === '天' && i > 0 && allText[i-1].match(/^[0-9]+$/)) result.day = parseInt(allText[i-1]);
      if (t.match(/^(春季|夏季|秋季|冬季)$/)) result.season = t;
      if (t === '水稻：' && i+1 < allText.length && allText[i+1].match(/^[0-9]+$/)) result.rice = parseInt(allText[i+1]);
      if (t === '红薯：' && i+1 < allText.length && allText[i+1].match(/^[0-9]+$/)) result.sweet = parseInt(allText[i+1]);
    }
    for (var i = 0; i < allText.length; i++) {
      var t = allText[i];
      if (t === '⚡' && i+2 < allText.length && allText[i+2] === '200') {
        if (allText[i+1].match(/^[0-9]+$/)) result.stamina = parseInt(allText[i+1]);
      }
      if (t === '❤️' && i+2 < allText.length && allText[i+2] === '200') {
        if (allText[i+1].match(/^[0-9]+$/)) result.health = parseInt(allText[i+1]);
      }
    }
    result.maxStamina = 200;
    result.maxHealth = 200;
    return JSON.stringify(result);
  } catch(e) {
    return JSON.stringify({error: e.message, stack: e.stack});
  }
})()
